module alu(obf_A, B, CTRL, RESULT);
input [31:0] obf_A, B;
input [1:0] CTRL;
output reg [31:0] RESULT;

always @(*) begin
    case (CTRL)
        2'b00: RESULT = obf_A + B;
        2'b01: RESULT = obf_A - B;
        2'b10: RESULT = obf_A & B;
        2'b11: RESULT = obf_A | B;
        default: RESULT = 0;
    endcase
end

endmodule
